function davisCalc(distKey,timeSec){
  var d=PACE_MODEL[distKey];if(!d)return null;
  var pts=d.pts;if(timeSec<=pts[0][0])return{cm10:pts[0][1],cm50:pts[0][2],cm90:pts[0][3],c10:pts[0][4],c50:pts[0][5],c90:pts[0][6],cp10:pts[0][7],cp50:pts[0][8],cp90:pts[0][9]};
  if(timeSec>=pts[pts.length-1][0])return{cm10:pts[pts.length-1][1],cm50:pts[pts.length-1][2],cm90:pts[pts.length-1][3],c10:pts[pts.length-1][4],c50:pts[pts.length-1][5],c90:pts[pts.length-1][6],cp10:pts[pts.length-1][7],cp50:pts[pts.length-1][8],cp90:pts[pts.length-1][9]};
  for(var i=0;i<pts.length-1;i++){if(timeSec>=pts[i][0]&&timeSec<=pts[i+1][0]){
    var f=(timeSec-pts[i][0])/(pts[i+1][0]-pts[i][0]);
    return{cm10:pts[i][1]+(pts[i+1][1]-pts[i][1])*f,cm50:pts[i][2]+(pts[i+1][2]-pts[i][2])*f,cm90:pts[i][3]+(pts[i+1][3]-pts[i][3])*f,c10:pts[i][4]+(pts[i+1][4]-pts[i][4])*f,c50:pts[i][5]+(pts[i+1][5]-pts[i][5])*f,c90:pts[i][6]+(pts[i+1][6]-pts[i][6])*f,cp10:pts[i][7]+(pts[i+1][7]-pts[i][7])*f,cp50:pts[i][8]+(pts[i+1][8]-pts[i][8])*f,cp90:pts[i][9]+(pts[i+1][9]-pts[i][9])*f};
  }}return null;
}
function davisPace(ms,unit){
  if(!ms||ms<=0)return"--";
  var d=unit==="/km"?1000:unit==="/400m"?400:unit==="/200m"?200:1609.34;
  var dec=d/(ms*60);var mm=Math.floor(dec);var ss=Math.round((dec-mm)*60);
  if(ss===60){mm++;ss=0;}
  return mm+":"+(ss<10?"0":"")+ss+unit;
}

var DAYS=["Mon","Tue","Wed","Thu","Fri","Sat","Sun"],FDAYS=["Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"],MO=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
function wkd(off){var t=new Date(),dow=t.getDay(),mo=dow===0?-6:1-dow,m=new Date(t);m.setDate(t.getDate()+mo+off*7);var a=[];for(var i=0;i<7;i++){var d=new Date(m);d.setDate(m.getDate()+i);a.push(d);}return a;}
function fd(d){return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0");}
function fs(d){return(d.getMonth()+1)+"/"+d.getDate();}
function fr(ds){return MO[ds[0].getMonth()]+" "+ds[0].getDate()+" - "+MO[ds[6].getMonth()]+" "+ds[6].getDate()+", "+ds[6].getFullYear();}
function gc(id){for(var i=0;i<CATS.length;i++){if(CATS[i].id===id)return CATS[i];}return null;}
function getDayArr(sch,k){var v=sch[k];if(!v)return[];if(Array.isArray(v))return v;return[v];}
function ini(name){var p=name.trim().split(/\s+/);return p.length>=2?p[0].charAt(0)+p[p.length-1].charAt(0):p[0].charAt(0);}
function genPin(){return String(Math.floor(1000+Math.random()*9000));}
function fmtMD(ds){var p=ds.split("-");var d=new Date(parseInt(p[0]),parseInt(p[1])-1,parseInt(p[2]));return["Sun","Mon","Tue","Wed","Thu","Fri","Sat"][d.getDay()]+", "+MO[d.getMonth()]+" "+d.getDate();}

