  /* ── Streak / Badge / Consistency helpers ── */
  var APP_START="2026-03-19";/* First day app was introduced to team */
  function getStreak(athId,mode){
    /* mode: "both"=checkin+log, "log"=log only, "checkin"=checkin only */
    if(!mode)mode="both";
    var streak=0;var d=new Date();d.setDate(d.getDate()-1);
    for(var i=0;i<365;i++){
      var dk=fd(d);if(dk<APP_START)break;
      var entries=wlog[dk]||[];
      var hasLog=entries.some(function(e){return e.athId===athId&&e.type!=="readiness";});
      var hasCheckin=entries.some(function(e){return e.athId===athId&&e.type==="readiness";});
      var ok=mode==="both"?(hasLog&&hasCheckin):mode==="log"?hasLog:hasCheckin;
      if(ok)streak++;else if(i===0){
        var td=fd(new Date());var te=wlog[td]||[];
        var tl=te.some(function(e){return e.athId===athId&&e.type!=="readiness";});
        var tc=te.some(function(e){return e.athId===athId&&e.type==="readiness";});
        var tok=mode==="both"?(tl&&tc):mode==="log"?tl:tc;
        if(tok)streak++;else break;
      }else break;
      d.setDate(d.getDate()-1);
    }return streak;
  }
  function getWeekBadges(athId){
    var badges=0;var now=new Date();var dow=now.getDay();var monOff=dow===0?-6:1-dow;
    for(var w=0;w<20;w++){
      var mon=new Date(now);mon.setDate(now.getDate()+monOff-w*7);mon.setHours(0,0,0,0);
      if(fd(mon)<APP_START)break;
      var days=0;
      for(var d=0;d<6;d++){/* Mon-Sat */
        var day=new Date(mon);day.setDate(mon.getDate()+d);var dk=fd(day);
        if(dk<APP_START)continue;
        if((wlog[dk]||[]).some(function(e){return e.athId===athId&&e.type!=="readiness";}))days++;
      }
      if(days>=6)badges++;
    }return badges;
  }
  function getConsistency(athId,period,monthStr){
    /* period: "week"=current Mon-Sat, "lastweek"=previous Mon-Sat, "month"=specific month, "overall"=since APP_START
       monthStr: "YYYY-MM" for month period (defaults to current month) */
    var now=new Date();var todayStr=fd(new Date());
    var start,end;
    if(period==="week"){
      var dow=now.getDay();var monOff=dow===0?-6:1-dow;
      start=new Date(now);start.setDate(now.getDate()+monOff);start.setHours(0,0,0,0);
      end=new Date(now);end.setHours(23,59,59,999);
    }else if(period==="lastweek"){
      var dow=now.getDay();var monOff=dow===0?-6:1-dow;
      start=new Date(now);start.setDate(now.getDate()+monOff-7);start.setHours(0,0,0,0);
      end=new Date(start);end.setDate(start.getDate()+5);end.setHours(23,59,59,999);/* Sat */
    }else if(period==="month"){
      var ms=monthStr||(now.getFullYear()+"-"+(now.getMonth()<9?"0":"")+(now.getMonth()+1));
      var mParts=ms.split("-");var mY=parseInt(mParts[0]);var mM=parseInt(mParts[1])-1;
      start=new Date(mY,mM,1);start.setHours(0,0,0,0);
      end=new Date(mY,mM+1,0);end.setHours(23,59,59,999);
      if(end>now)end=new Date(now);end.setHours(23,59,59,999);
    }else{
      var sp2=APP_START.split("-");start=new Date(parseInt(sp2[0]),parseInt(sp2[1])-1,parseInt(sp2[2]));
      start.setHours(0,0,0,0);
      end=new Date(now);end.setHours(23,59,59,999);
    }
    /* Don't go before APP_START */
    var sp=APP_START.split("-");var appStart=new Date(parseInt(sp[0]),parseInt(sp[1])-1,parseInt(sp[2]));
    appStart.setHours(0,0,0,0);
    if(start<appStart)start=appStart;
    var totalDays=0;var logDays=0;var checkinDays=0;var logEntries=0;var checkinEntries=0;var bonusDays=0;
    var d=new Date(start);
    while(d<=end){
      var dow=d.getDay();
      if(dow>=1&&dow<=6){/* Mon-Sat */
        var dk=fd(d);var entries=wlog[dk]||[];
        var dayLogs=entries.filter(function(e){return e.athId===athId&&e.type!=="readiness";});
        var dayCheckins=entries.filter(function(e){return e.athId===athId&&e.type==="readiness";});
        var hasLog=dayLogs.length>0;
        var hasCheckin=dayCheckins.length>0;
        var isToday=(dk===todayStr);
        if(!isToday||(isToday&&(hasLog||hasCheckin))){totalDays++;}
        if(hasLog)logDays++;
        if(hasCheckin)checkinDays++;
        if(hasLog&&hasCheckin)bonusDays++;
        logEntries+=dayLogs.length;
        checkinEntries+=dayCheckins.length;
      }
      d.setDate(d.getDate()+1);
    }
    return{
      logPct:totalDays>0?Math.round(logDays/totalDays*100):0,
      checkinPct:totalDays>0?Math.round(checkinDays/totalDays*100):0,
      totalDays:totalDays,logDays:logDays,checkinDays:checkinDays,
      logEntries:logEntries,checkinEntries:checkinEntries,bonusDays:bonusDays
    };
  }
