                      <div style={{fontSize:9,color:"#8E44AD",fontFamily:"monospace",opacity:0.7}}>Range: {davisPace(pcRes.cm10,"/mi").replace("/mi","")}{"\u2013"}{davisPace(pcRes.cm90,"/mi")}</div>
